import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Observable, BehaviorSubject, switchMap, catchError, of, tap } from 'rxjs';
import { Task } from '../../core/models/task.model';
import { TaskService } from '../../core/services/task.service';
import { AddTaskFormComponent } from './components/add-task-form/add-task-form.component';
import { TaskListComponent } from './components/task-list/task-list.component';

@Component({
  selector: 'app-task-manager',
  standalone: true,
  imports: [CommonModule, AddTaskFormComponent, TaskListComponent],
  templateUrl: './task-manager.component.html',
  styleUrls: ['./task-manager.component.scss']
})
export class TaskManagerComponent implements OnInit {
  private taskService = inject(TaskService);

  tasks$!: Observable<Task[]>;
  error: string | null = null;
  loading = true;

  private refreshTasks$ = new BehaviorSubject<void>(undefined);

  ngOnInit() {
    this.tasks$ = this.refreshTasks$.pipe(
      tap(() => {
        this.loading = true;
        this.error = null;
      }),
      switchMap(() => this.taskService.getTasks()),
      tap(() => this.loading = false),
      catchError(err => {
        this.error = 'Failed to load tasks.';
        this.loading = false;
        console.error(err);
        return of([]);
      })
    );
  }

  handleAddTask(title: string) {
    this.taskService.addTask(title).pipe(
      catchError(err => {
        this.error = 'Failed to add task.';
        console.error(err);
        return of(null);
      })
    ).subscribe(task => {
      if (task) {
        this.refreshTasks$.next();
      }
    });
  }

  handleCompleteTask(taskId: number) {
    this.taskService.deleteTask(taskId).pipe(
      catchError(err => {
        this.error = 'Failed to complete task.';
        console.error(err);
        return of(null);
      })
    ).subscribe(result => {
      // On successful deletion from service (which updates the signal), refresh the view
      if (result === undefined) {
         this.refreshTasks$.next();
      }
    });
  }
}

