import { Injectable, signal } from '@angular/core';
import { of, Observable, throwError, delay } from 'rxjs';
import { Task } from '../models/task.model';

@Injectable({
  providedIn: 'root'
})
export class TaskService {
  private tasks = signal<Task[]>([]);
  private initialTasks: Task[] = [
    {
      taskId: 1,
      title: 'Finish the project report',
      status: 'pending',
      createdAt: '2023-10-27T10:00:00Z',
      updatedAt: '2023-10-27T10:00:00Z'
    },
    {
      taskId: 2,
      title: 'Buy groceries',
      status: 'pending',
      createdAt: '2023-10-27T10:05:00Z',
      updatedAt: '2023-10-27T10:05:00Z'
    },
    {
      taskId: 3,
      title: 'Schedule a dentist appointment',
      status: 'pending',
      createdAt: '2023-10-28T11:00:00Z',
      updatedAt: '2023-10-28T11:00:00Z'
    }
  ];

  constructor() {
    this.tasks.set(this.initialTasks);
  }

  getTasks(): Observable<Task[]> {
    // Mocking an API call with a delay
    return of(this.tasks()).pipe(delay(500));
  }

  addTask(title: string): Observable<Task> {
    if (!title.trim()) {
      return throwError(() => new Error('Task title cannot be empty.'));
    }

    const newTask: Task = {
      taskId: Math.floor(Math.random() * 1000) + 1, // Mocking ID generation
      title: title,
      status: 'pending',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };

    this.tasks.update(tasks => [...tasks, newTask]);

    // Mocking an API call with a delay
    return of(newTask).pipe(delay(300));
  }

  deleteTask(taskId: number): Observable<void> {
    const taskExists = this.tasks().some(task => task.taskId === taskId);
    if (!taskExists) {
      return throwError(() => new Error(`Task with id ${taskId} not found.`));
    }

    this.tasks.update(tasks => tasks.filter(task => task.taskId !== taskId));

    // Mocking an API call with a delay
    return of(undefined).pipe(delay(300));
  }
}

