import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, of, throwError } from 'rxjs';
import { delay, map } from 'rxjs/operators';
import { Ticket, ActivityNote, TicketStatus, TicketPriority, TicketSeverity, TicketType } from '../../../shared/models/ticket.model';
import { MOCK_TICKETS, MOCK_ACTIVITY_NOTES } from '../../../shared/mock-data/mock-tickets';
import { AuthService } from '../../../core/services/auth.service';

@Injectable({
  providedIn: 'root'
})
export class TicketService {
  private tickets: Ticket[] = MOCK_TICKETS;

  constructor(private http: HttpClient, private authService: AuthService) {}

  // In a real app, this would make an HTTP GET request to /api/tickets
  getAllTickets(): Observable<Ticket[]> {
    console.log('Mock TicketService: getAllTickets called');
    const currentUser = this.authService.currentUserValue;

    // Simulate role-based filtering
    let filteredTickets = this.tickets;
    if (currentUser && currentUser.role === 'Requester') {
        filteredTickets = this.tickets.filter(t => t.creator_id === currentUser.id);
    }

    return of(filteredTickets).pipe(delay(500));
  }

  // In a real app, this would make an HTTP GET request to /api/tickets/{id}
  getTicketById(id: number): Observable<Ticket | undefined> {
    console.log(`Mock TicketService: getTicketById called with id: ${id}`);
    const ticket = this.tickets.find(t => t.id === id);
    if (ticket) {
      // Add mock activity notes
      ticket.activity_notes = MOCK_ACTIVITY_NOTES.filter(note => note.ticket_id === id);
    }
    return of(ticket).pipe(delay(300));
  }

  // In a real app, this would make an HTTP POST request to /api/tickets
  createTicket(ticketData: Partial<Ticket>): Observable<Ticket> {
    console.log('Mock TicketService: createTicket called with data:', ticketData);
    const currentUser = this.authService.currentUserValue;
    if (!currentUser) {
      return throwError(() => new Error('User not logged in'));
    }

    const newTicket: Ticket = {
      id: Math.max(...this.tickets.map(t => t.id)) + 1,
      title: ticketData.title || 'No Title',
      description: ticketData.description || 'No Description',
      priority: ticketData.priority || TicketPriority.Medium,
      severity: ticketData.severity || TicketSeverity.Medium,
      status: TicketStatus.New,
      type: ticketData.type || TicketType.Incident,
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
      creator_id: currentUser.id,
      assignee_id: null,
      activity_notes: []
    };

    this.tickets.push(newTicket);
    return of(newTicket).pipe(delay(500));
  }

  // In a real app, this would make an HTTP PUT request to /api/tickets/{id}
  updateTicket(id: number, updates: Partial<Ticket>): Observable<Ticket | undefined> {
    console.log(`Mock TicketService: updateTicket called for id ${id} with updates:`, updates);
    let ticket = this.tickets.find(t => t.id === id);
    if (ticket) {
      ticket = { ...ticket, ...updates, updated_at: new Date().toISOString() };
      this.tickets = this.tickets.map(t => t.id === id ? ticket! : t);
      return of(ticket).pipe(delay(400));
    }
    return throwError(() => new Error('Ticket not found'));
  }

  // In a real app, this would make an HTTP POST request to /api/tickets/{id}/notes
  addActivityNote(ticketId: number, noteText: string): Observable<ActivityNote> {
    console.log(`Mock TicketService: addActivityNote for ticket ${ticketId} with note: "${noteText}"`);
    const currentUser = this.authService.currentUserValue;
    if (!currentUser) {
      return throwError(() => new Error('User not logged in'));
    }

    const newNote: ActivityNote = {
      id: MOCK_ACTIVITY_NOTES.length + 1,
      note: noteText,
      created_at: new Date().toISOString(),
      user_id: currentUser.id,
      ticket_id: ticketId
    };

    MOCK_ACTIVITY_NOTES.push(newNote);

    // Also add a log to the ticket itself
    const ticket = this.tickets.find(t => t.id === ticketId);
    if(ticket) {
        ticket.updated_at = new Date().toISOString();
    }

    return of(newNote).pipe(delay(400));
  }
}

