import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { BehaviorSubject, Observable, of } from 'rxjs';
import { map, tap, delay } from 'rxjs/operators';
import { User } from '../../shared/models/user.model';
import { Router } from '@angular/router';

@Injectable({
  providedIn: 'root'
})
export class AuthService {
  private currentUserSubject: BehaviorSubject<User | null>;
  public currentUser$: Observable<User | null>;

  constructor(private http: HttpClient, private router: Router) {
    const userJson = localStorage.getItem('currentUser');
    this.currentUserSubject = new BehaviorSubject<User | null>(userJson ? JSON.parse(userJson) : null);
    this.currentUser$ = this.currentUserSubject.asObservable();
  }

  public get currentUserValue(): User | null {
    return this.currentUserSubject.value;
  }

  login(username: string, password: string): Observable<User> {
    // MOCK API CALL
    console.log(`Attempting login for user: ${username}`);

    // In a real app, this would be a POST request to '/api/auth/login'
    // We mock the response based on username
    let mockUser: User;
    let role: 'Agent' | 'Requester' | 'Admin' = 'Requester';

    if (username.includes('agent')) {
      role = 'Agent';
    } else if (username.includes('admin')) {
      role = 'Admin';
    }

    mockUser = {
      id: 1,
      username: username,
      role: role,
      token: 'mock-jwt-token-for-' + username
    };

    return of(mockUser).pipe(
      delay(500), // Simulate network latency
      tap(user => {
        localStorage.setItem('currentUser', JSON.stringify(user));
        this.currentUserSubject.next(user);
        console.log('Login successful, user set:', user);
      })
    );
  }

  logout(): void {
    localStorage.removeItem('currentUser');
    this.currentUserSubject.next(null);
    this.router.navigate(['/login']);
  }
}

