import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { Observable, of, switchMap } from 'rxjs';
import { Ticket, TicketStatus, ActivityNote } from '../../../../shared/models/ticket.model';
import { TicketService } from '../../services/ticket.service';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { User } from '../../../../shared/models/user.model';
import { UserService } from '../../../admin/services/user.service';
import { AuthService } from '../../../../core/services/auth.service';
import { finalize } from 'rxjs/operators';

@Component({
  selector: 'app-ticket-details',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './ticket-details.component.html',
  styleUrls: ['./ticket-details.component.scss']
})
export class TicketDetailsComponent implements OnInit {
  ticket$: Observable<Ticket | undefined> | undefined;
  agents$: Observable<User[]> | undefined;
  currentUser: User | null = null;

  updateForm: FormGroup;
  noteForm: FormGroup;

  ticketStatuses = Object.values(TicketStatus);
  isLoading = false;
  isUpdating = false;
  isAddingNote = false;
  error: string | null = null;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private ticketService: TicketService,
    private userService: UserService,
    private authService: AuthService,
    private fb: FormBuilder
  ) {
    this.authService.currentUser$.subscribe(user => this.currentUser = user);

    this.updateForm = this.fb.group({
      status: [''],
      assignee_id: [null]
    });

    this.noteForm = this.fb.group({
      note: ['', Validators.required]
    });
  }

  ngOnInit(): void {
    this.isLoading = true;
    this.ticket$ = this.route.paramMap.pipe(
      switchMap(params => {
        const id = params.get('id');
        if (id) {
          return this.ticketService.getTicketById(+id).pipe(
            finalize(() => this.isLoading = false)
          );
        }
        this.router.navigate(['/tickets']);
        return of(undefined);
      })
    );

    this.ticket$.subscribe(ticket => {
      if (ticket) {
        this.updateForm.patchValue({
          status: ticket.status,
          assignee_id: ticket.assignee_id
        });
      }
    });

    if (this.currentUser?.role === 'Agent' || this.currentUser?.role === 'Admin') {
      this.agents$ = this.userService.getUsersByRole('Agent');
    }
  }

  onUpdateTicket(): void {
    if (this.updateForm.invalid) return;

    this.isUpdating = true;
    const ticketId = +this.route.snapshot.params['id'];
    const updates = this.updateForm.value;

    this.ticketService.updateTicket(ticketId, updates).pipe(
      finalize(() => this.isUpdating = false)
    ).subscribe({
      next: updatedTicket => {
        // Manually trigger a refresh of the ticket data
        this.ticket$ = this.ticketService.getTicketById(ticketId);
      },
      error: err => this.error = 'Failed to update ticket.'
    });
  }

  onAddNote(): void {
    if (this.noteForm.invalid) return;

    this.isAddingNote = true;
    const ticketId = +this.route.snapshot.params['id'];
    const note = this.noteForm.value.note;

    this.ticketService.addActivityNote(ticketId, note).pipe(
      finalize(() => this.isAddingNote = false)
    ).subscribe({
      next: newNote => {
        this.noteForm.reset();
        // Manually trigger a refresh of the ticket data
        this.ticket$ = this.ticketService.getTicketById(ticketId);
      },
      error: err => this.error = 'Failed to add note.'
    });
  }

  getSeverityClass(severity: string): string {
    switch (severity) {
      case 'Critical': return 'bg-red-500 text-white';
      case 'High': return 'bg-yellow-500 text-black';
      case 'Medium': return 'bg-blue-500 text-white';
      case 'Low': return 'bg-green-500 text-white';
      default: return 'bg-gray-300 text-black';
    }
  }

  getStatusClass(status: string): string {
    switch (status) {
      case 'New':
      case 'Submitted':
        return 'bg-blue-200 text-blue-800';
      case 'In Progress':
      case 'In Review':
        return 'bg-yellow-200 text-yellow-800';
      case 'Resolved':
      case 'Approved':
      case 'Completed':
        return 'bg-green-200 text-green-800';
      case 'Closed':
      case 'Rejected':
        return 'bg-gray-400 text-white';
      default:
        return 'bg-gray-200 text-gray-800';
    }
  }
}

